// Defensive cross-indexer cap gate. Public tacitscan endpoint returns the
// set of T_PETCH asset_ids it has confirmed minted-out per SPEC §5.9
// (Pedersen + parent + amount + height-window). Used to disable the Mint
// button when the worker's `cumulative_minted` is stale (e.g. the cron
// missed a dense-mint asset and the dapp's browser-side fallback hasn't
// caught up). Failure-mode is graceful: if tacitscan is unreachable, the
// dapp falls back to worker-only state — identical to today's behavior.
// Use the www.tacitscan.io subdomain directly: the apex tacitscan.io
// 307-redirects to www, and a browser fetch from the apex hits CSP recheck
// on the redirected URL. The dapp's CSP whitelist is per-host, so apex →
// www would need both hosts allowed. Plus the apex redirect adds ~1s round-
// trip which the 3.5s timeout below can't reliably absorb on slow networks.
// Hitting www directly is single-hop and stays within budget.
const TACITSCAN_MINTED_OUT_URL = 'https://www.tacitscan.io/api/minted-out';
const DROPS_URL = WORKER_BASE ? WORKER_BASE + '/drops' : '';
const DROP_URL  = (rootHex) => WORKER_BASE ? `${WORKER_BASE}/drops/${rootHex}` : '';
// Cross-indexer minted-out gate. Cached per network for 60s — cap state
// can't flip more frequently than blocks land, and the endpoint itself
// edge-caches at 30s, so 60s in the dapp tolerates one stale poll
// without falsely re-enabling a button that should stay disabled.
// Always returns a Set (possibly empty) so callers don't need null checks.
let _tacitscanMintedOutCache = new Map(); // network -> { set, fetchedAt }
const _TACITSCAN_TTL_MS = 60_000;
async function fetchTacitscanMintedOut(network) {
  const cached = _tacitscanMintedOutCache.get(network);
  if (cached && Date.now() - cached.fetchedAt < _TACITSCAN_TTL_MS) return cached.set;
  try {
    const r = await fetch(`${TACITSCAN_MINTED_OUT_URL}?network=${encodeURIComponent(network)}`, {
      signal: AbortSignal.timeout(3500),
    });
    if (!r.ok) return cached?.set ?? new Set();
    const data = await r.json();
    // Only trust the response if it self-identifies as the right network.
    // Defensive: a misconfigured indexer that mainnet-tags signet rows would
    // otherwise mis-disable the wrong assets here. Mismatched payload =
    // don't override worker state.
    if (data && data.network && data.network !== network) {
      return cached?.set ?? new Set();
    }
    const set = new Set((data?.assets || []).map((a) => a.asset_id).filter(Boolean));
    _tacitscanMintedOutCache.set(network, { set, fetchedAt: Date.now() });
    return set;
  } catch {
    return cached?.set ?? new Set();
  }
}

// Append the active network as a query param. The worker's registry endpoints
// are network-scoped. The dapp defaults to mainnet; users opt into signet
// via the network selector.
function withNet(url, extra = '') {
  if (!url) return '';
  const sep = url.includes('?') ? '&' : '?';
  const params = `network=${encodeURIComponent(NET.name)}${extra ? '&' + extra : ''}`;
  return `${url}${sep}${params}`;
}

// External wallets report their network with their own vocabulary
// (UniSat: 'livenet'/'testnet'/'signet'; sats-connect: 'Mainnet'/'Signet'/...).
// Normalize to our two-network vocabulary. Returns null for unsupported nets
// (testnet3/4, regtest) so the connect flow can warn and bail.
function normalizeWalletNetwork(raw) {
  const v = String(raw || '').toLowerCase();
  if (v === 'mainnet' || v === 'livenet') return 'mainnet';
  if (v === 'signet') return 'signet';
  return null;
}

// Reconcile the dApp's network with the connected wallet's. Standard
// Bitcoin-dApp behavior: the wallet drives. We don't add a redundant "are
// you sure?" gate here — the wallet's own send popup is the per-tx consent
// for real funds. The manual selector flip (burner mode) keeps its consent
// gate because there's no wallet popup in that path.
//
// Returns:
//   'ok'          — networks match, caller proceeds
//   'reload'      — switching net + reloading; caller must bail
//   'unsupported' — wallet on testnet/regtest; we disconnected; caller bails
function reconcileWalletNetwork(state) {
  if (!state) return 'ok';
  const norm = normalizeWalletNetwork(state.network);
  if (!norm) {
    toast(`Wallet network "${state.network}" is not supported. Tacit runs on signet + mainnet only — switch your wallet's network and reconnect.`, 'error');
    extWallet.disconnect();
    wallet.ext = null;
    return 'unsupported';
  }
  if (norm === NET.name) return 'ok';
  // Wallet is on a supported network we're not yet on. The user actively
  // chose that network in their wallet UI, so treat that as consent — also
  // record it in MAINNET_OK_KEY so a later disconnect to burner mode doesn't
  // re-prompt for something they already opted into.
  if (norm === 'mainnet') localStorage.setItem('tacit-mainnet-consented-v1', '1');
  localStorage.setItem(NET_KEY, norm);
  toast(`Switching to ${norm} to match your wallet…`, 'success');
  // Brief delay so the toast renders before reload nukes the page.
  setTimeout(() => location.reload(), 600);
  return 'reload';
}
