    const raw = localStorage.getItem(_outspendCacheStorageKey());
    if (!raw) return;
    const parsed = JSON.parse(raw);
    if (!parsed || parsed.v !== 1 || !parsed.entries) return;
    for (const [k, v] of Object.entries(parsed.entries)) _outspendSpentCache.set(k, v);
